    b"%7\r\n$6\r\nserver\r\n$5\r\nredis\r\n$7\r\nversion\r\n$5\r\n7.4.0\r\n"
    b"$5\r\nproto\r\n:3\r\n$2\r\nid\r\n:1\r\n$4\r\nmode\r\n$10\r\nstandalone\r\n"
    b"$4\r\nrole\r\n$6\r\nmaster\r\n$7\r\nmodules\r\n*0\r\n"
)

# Push notification frames, byte-for-byte identical to the sync MockSocket fixtures.
MIGRATING_PUSH = b">3\r\n$9\r\nMIGRATING\r\n:1\r\n:10\r\n"
MIGRATED_PUSH = b">2\r\n$8\r\nMIGRATED\r\n:1\r\n"
FAILING_OVER_PUSH = b">3\r\n$12\r\nFAILING_OVER\r\n:1\r\n:10\r\n"
FAILED_OVER_PUSH = b">2\r\n$11\r\nFAILED_OVER\r\n:1\r\n"
MOVING_NONE_PUSH = f">4\r\n$6\r\nMOVING\r\n:1\r\n:{MOVING_TIMEOUT}\r\n_\r\n".encode()
MOVING_PUSH = (
    f">4\r\n$6\r\nMOVING\r\n:1\r\n:{MOVING_TIMEOUT}\r\n+{AFTER_MOVING_ADDRESS}\r\n"
).encode()


def _script_response(data: bytes) -> bytes:
    """Reproduce the sync MockSocket.send() command -> response scripting."""
    if b"HELLO" in data:
        return HELLO_RESP3_RESPONSE

    if b"MAINT_NOTIFICATIONS" in data and b"internal-ip" in data:
        return b"+ERROR\r\n"

    if b"SET" in data:
        response = b"+OK\r\n"
        if b"key_receive_migrating" in data:
            response = MIGRATING_PUSH + response
        elif b"key_receive_migrated" in data:
            response = MIGRATED_PUSH + response
        elif b"key_receive_failing_over" in data:
            response = FAILING_OVER_PUSH + response
        elif b"key_receive_failed_over" in data:
            response = FAILED_OVER_PUSH + response
        elif b"key_receive_moving_none" in data:
            response = MOVING_NONE_PUSH + response
        elif b"key_receive_moving" in data:
            response = MOVING_PUSH + response
        return response

    if b"GET" in data:
        if b"hello" in data:
            return b"$5\r\nworld\r\n"
        if b"key_receive_moving_0" in data:
            return b"$8\r\nvalue3_0\r\n"
        if b"key_receive_migrated_0" in data:
            return b"$13\r\nmigrated_value\r\n"
        if b"key_receive_migrating" in data:
            return b"$6\r\nvalue2\r\n"
        if b"key_receive_migrated" in data:
            return b"$6\r\nvalue3\r\n"
        if b"key_receive_failing_over" in data:
            return b"$6\r\nvalue4\r\n"
        if b"key_receive_failed_over" in data:
            return b"$6\r\nvalue5\r\n"
        if b"key1" in data:
            return b"$6\r\nvalue1\r\n"
        return b"$-1\r\n"

    return b"+OK\r\n"


class FakeSocket:
    """Fake object returned by ``writer.transport.get_extra_info("socket")``."""

    def __init__(self, host: str, port: int):
        self._host = host
        self._port = port
        self.connected = True
        self.closed = False
        self._timeout = None

    def getpeername(self) -> Tuple[str, int]:
        return (self._host, self._port)

    def getsockname(self) -> Tuple[str, int]:
        return (self._host, 12345)

    def settimeout(self, timeout) -> None:
        self._timeout = timeout

    def gettimeout(self):
        return self._timeout


class MockWriter:
    """
    Scripted double for ``asyncio.StreamWriter``.

    Every ``write``/``writelines`` call runs the command through
    :func:`_script_response` and immediately feeds the response bytes into the
    paired ``asyncio.StreamReader``, so the parser can read them back without any
    real I/O or extra scheduling.
    """

    def __init__(self, reader: asyncio.StreamReader, host: str, port: int):
        self.reader = reader
        self.host = host
        self.port = port
        self.sent_data: List[bytes] = []
        self._closed = False
        self.socket = FakeSocket(host, port)

        class _Transport:
            def __init__(self, outer: "MockWriter"):
                self._outer = outer

            def get_extra_info(self_inner, name, default=None):
                if name == "socket":
                    return self_inner._outer.socket
                return default

        self.transport = _Transport(self)

    def write(self, data: bytes) -> None:
        self._handle(data)

    def writelines(self, chunks) -> None:
        if isinstance(chunks, (bytes, bytearray)):
            data = bytes(chunks)
        else:
            data = b"".join(chunks)
        self._handle(data)

    def _handle(self, data: bytes) -> None:
        self.sent_data.append(data)
        if self._closed:
            return
        response = _script_response(data)
        if response:
            self.reader.feed_data(response)

    async def drain(self) -> None:
        return None

    def close(self) -> None:
        if self._closed:
            return
        self._closed = True
        self.socket.connected = False
        self.socket.closed = True
        try:
            if not self.reader.at_eof():
                self.reader.feed_eof()
        except Exception:
            pass

    async def wait_closed(self) -> None:
        return None

    def is_closing(self) -> bool:
        return self._closed


class AsyncMockServerMixin:
    """
    Base class providing a patched ``asyncio.open_connection`` and bookkeeping of
    every mock connection created during a test, mirroring
    ``TestMaintenanceNotificationsBase`` from the sync handling suite.
    """

    def setup_method(self):
        self.mock_writers: List[MockWriter] = []
        self.open_connection_targets: List[Tuple[Optional[str], Optional[int]]] = []

        async def _factory(*args, **kwargs):
            host = kwargs.get("host")
            port = kwargs.get("port")
            reader = asyncio.StreamReader()
            writer = MockWriter(reader, host, port)
            self.mock_writers.append(writer)
            self.open_connection_targets.append((host, port))
            return reader, writer

        self._open_connection_patcher = patch(
            "asyncio.open_connection", side_effect=_factory
        )
        self._open_connection_patcher.start()

    def teardown_method(self):
        self._open_connection_patcher.stop()

    def _connected_count(self) -> int:
        return sum(1 for w in self.mock_writers if w.socket.connected)

    def _closed_count(self) -> int:
        return sum(1 for w in self.mock_writers if w.socket.closed)

